@group(0) @binding(4) var<storage, read> w_zp: array<u32>;
@group(0) @binding(5) var<storage, read> bias: array<f16>;
@group(0) @binding(6) var<storage, read_write> y: array<f16>;

const BLOCK: u32 = 32u;
const TR: u32 = 4u;
const WG: u32 = 64u;
